  ('social-worker-moex-03820', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某兒少社工酷愛清潔，在家訪時，發現個案居家環境堆滿各種囤積物品，其評估母親的精神狀態 不佳，擬強制就醫並安置兒少。兒童強烈表示不想與母親分開，央求社工不要通報與安置。下列 何者非屬社工面對的倫理難題？', '["保密與隱私權", "案主自我決定與專業父權主義", "應否揭發機構內部不當行為", "社工個人的價值涉入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03821', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關個人復原力，下列敘述何者正確？', '["復原力是一個動態的過程，是一種良好的適應，是一種個人力量的恢復", "從結構的觀點來看，復原力是個人處於社會結構的結果", "社會工作者必須以建構保護因子為目標，培養弱勢者的復原力", "復原力主要是個人先天具備的某些能力特質，而非後天環境重要因素所培育而成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03822', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '因社工師侵權行為而造成案主受損害，案主可依下列何種法律，請求機構與社工師負連帶賠償責 任？', '["犯罪防治法", "行政法", "刑法", "民法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03823', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer（1995）認為業務過失可以區分為三種形式，下列何者錯誤？', '["濫權", "瀆職", "索賄", "怠職"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03824', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於照顧身心障礙子女的優勢觀點，下列何者正確？', '["照顧者生活一切以子女為優先，犧牲自我", "照顧者為了子女，爭取機會並學習和專業團隊溝通", "照顧者遵從醫囑，提供子女治療性照顧", "照顧者對子女的愧疚感，有助於家庭凝聚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03825', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Banks認為依據社會工作者的道德立場與工作環境，可以分為那四種實務模式？', '["承諾/激進模式、人本模式、社會行政模式、執業模式", "承諾/激進模式、專業模式、技術官僚模式、準事業模式", "承諾/激進模式、醫療模式、技術官僚模式、執業模式", "承諾/激進模式、專業模式、社會行政模式、準事業模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03826', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「家庭復原力」具有動態發展的特質，並且會與環境相互交流。關於「家庭復原力」之相關概念 的敘述，下列何者錯誤？', '["「不顯現負向結果」與「顯現正向調適」都是家庭展現復原力的形式", "家庭組織是指一套涵蓋價值觀、態度、偏見與假設的體系", "家庭的風險因子可能會隨著家庭成員的年齡而有所變化", "家庭儀式可促成家庭的穩定性與可預測性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03827', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社區工作的敘述，下列何者錯誤？', '["臺灣社區工作與福利工作並非自始相互結合", "社區概念僅與特定地理區域連結", "老舊市區經濟不振，政府推動城區更新，翻轉老舊市區樣貌，運用的是社區發展模式", "為建立在地連結，志工式的服務方式，社區工作方能紮根經營"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03828', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '原住民移居都市後，常從事骯髒、危險及辛苦之工作（俗稱3K產業），加之遠離原有的支持網絡， 子女照顧、貧窮等問題導致家庭關係緊張、兒虐與家暴，下列何種改善做法錯誤？', '["運用部落互助概念照顧幼兒，幼兒園作息配合家長工作時間", "家暴不是個別家庭的事，應重視其所屬生態環境條件", "應積極協助轉介從事3K工作原住民職訓，以提升職能，擺脫貧窮", "都市社區原住民服務中心應依部落特性設計服務內容"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03829', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關親職教養技巧訓練的敘述，下列何者錯誤？', '["父母要能體認孩子行為與教養行為間的關係", "主張父母要學會對孩子行為有不同回應方式", "父母要能處理自己的創傷經驗後再執行親職", "改變父母認為「問題只出在孩子身上」的看法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:21+00:00", "source_pdf_sha1": "2b032161fc60", "answer_pdf_sha1": "bc7a447ea8d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
